CREATE TABLE public.workflow_stages (created_at timestamp without time zone NOT NULL DEFAULT now(), name text NOT NULL, id integer NOT NULL DEFAULT nextval('workflow_stages_id_seq'::regclass), order_index integer NOT NULL, description text, auto_advance boolean NOT NULL DEFAULT true, timeout_minutes integer, workflow_definition_id integer NOT NULL, code character varying NOT NULL, retry_config jsonb, handler_key text, requires_review boolean NOT NULL DEFAULT false, issue_blocks_severity text, updated_at timestamp without time zone NOT NULL DEFAULT now(), configuration jsonb DEFAULT '{}'::jsonb, is_required boolean NOT NULL DEFAULT true, stage_type text NOT NULL DEFAULT 'automated'::text, is_active boolean NOT NULL DEFAULT true);
CREATE TABLE public.workflow_tasks (due_at timestamp without time zone, updated_at timestamp without time zone NOT NULL DEFAULT now(), description text, status text NOT NULL DEFAULT 'pending'::text, assigned_to_id character varying, created_at timestamp without time zone NOT NULL DEFAULT now(), ticket_id integer NOT NULL, priority text NOT NULL DEFAULT 'normal'::text, assigned_at timestamp without time zone, completed_at timestamp without time zone, created_by character varying, completed_by character varying, completion_notes text, title text NOT NULL, issue_id integer, task_type text NOT NULL DEFAULT 'action'::text, id integer NOT NULL DEFAULT nextval('workflow_tasks_id_seq'::regclass), assigned_to_role text);
CREATE TABLE public.workflow_ticket_stages (created_at timestamp without time zone NOT NULL DEFAULT now(), status text NOT NULL DEFAULT 'pending'::text, review_decision text, error_message text, updated_at timestamp without time zone NOT NULL DEFAULT now(), last_executed_by character varying, execution_count integer NOT NULL DEFAULT 0, last_executed_at timestamp without time zone, ticket_id integer NOT NULL, completed_at timestamp without time zone, reviewed_by character varying, review_notes text, stage_id integer NOT NULL, reviewed_at timestamp without time zone, handler_response jsonb, started_at timestamp without time zone, result text, id integer NOT NULL DEFAULT nextval('workflow_ticket_stages_id_seq'::regclass));
CREATE TABLE public.workflow_tickets (created_at timestamp without time zone NOT NULL DEFAULT now(), risk_level text, risk_score integer, completed_at timestamp without time zone, last_reviewed_at timestamp without time zone, entity_id integer NOT NULL, review_count integer NOT NULL DEFAULT 0, priority text NOT NULL DEFAULT 'normal'::text, status text NOT NULL DEFAULT 'submitted'::text, entity_type text NOT NULL, metadata jsonb DEFAULT '{}'::jsonb, ticket_number character varying NOT NULL, workflow_definition_id integer NOT NULL, updated_at timestamp without time zone NOT NULL DEFAULT now(), last_reviewed_by character varying, submitted_at timestamp without time zone NOT NULL DEFAULT now(), id integer NOT NULL DEFAULT nextval('workflow_tickets_id_seq'::regclass), started_at timestamp without time zone, due_at timestamp without time zone, current_stage_id integer, assigned_at timestamp without time zone, assigned_to_id character varying, sub_status text);
CREATE TABLE public.workflow_transitions (to_value text, notes text, triggered_by_system boolean NOT NULL DEFAULT false, to_stage_id integer, from_value text, triggered_by character varying, reason text, created_at timestamp without time zone NOT NULL DEFAULT now(), id integer NOT NULL DEFAULT nextval('workflow_transitions_id_seq'::regclass), ticket_id integer NOT NULL, transition_type text NOT NULL, from_stage_id integer);